PRAGMA defer_foreign_keys=TRUE;
CREATE TABLE users (
  id TEXT PRIMARY KEY,
  full_name TEXT NOT NULL,
  email TEXT NOT NULL UNIQUE,
  role TEXT NOT NULL CHECK (role IN ('ADMIN', 'TEACHER', 'STUDENT')),
  created_at TEXT NOT NULL
);
CREATE TABLE classes (
  id TEXT PRIMARY KEY,
  name TEXT NOT NULL,
  description TEXT,
  teacher_id TEXT NOT NULL,
  created_at TEXT NOT NULL, subject TEXT NOT NULL DEFAULT 'Ерөнхий', grade INTEGER NOT NULL DEFAULT 0,
  FOREIGN KEY (teacher_id) REFERENCES users(id) ON DELETE RESTRICT
);
CREATE TABLE class_students (
  id TEXT PRIMARY KEY,
  class_id TEXT NOT NULL,
  student_id TEXT NOT NULL,
  UNIQUE (class_id, student_id),
  FOREIGN KEY (class_id) REFERENCES classes(id) ON DELETE CASCADE,
  FOREIGN KEY (student_id) REFERENCES users(id) ON DELETE CASCADE
);
CREATE TABLE question_banks (
  id TEXT PRIMARY KEY,
  title TEXT NOT NULL,
  description TEXT,
  owner_id TEXT NOT NULL,
  created_at TEXT NOT NULL, subject TEXT NOT NULL DEFAULT 'Асуултын сан', grade INTEGER NOT NULL DEFAULT 10, topic TEXT NOT NULL DEFAULT 'Ерөнхий', visibility TEXT NOT NULL DEFAULT 'PRIVATE' CHECK (visibility IN ('PRIVATE', 'PUBLIC')),
  FOREIGN KEY (owner_id) REFERENCES users(id) ON DELETE RESTRICT
);
CREATE TABLE exam_questions (
  id TEXT PRIMARY KEY,
  exam_id TEXT NOT NULL,
  question_id TEXT NOT NULL,
  points INTEGER NOT NULL,
  display_order INTEGER NOT NULL,
  UNIQUE (exam_id, question_id),
  UNIQUE (exam_id, display_order),
  FOREIGN KEY (exam_id) REFERENCES "exams_old"(id) ON DELETE CASCADE,
  FOREIGN KEY (question_id) REFERENCES questions(id) ON DELETE CASCADE
);
CREATE TABLE attempts (
  id TEXT PRIMARY KEY,
  exam_id TEXT NOT NULL,
  student_id TEXT NOT NULL,
  status TEXT NOT NULL CHECK (status IN ('IN_PROGRESS', 'SUBMITTED', 'GRADED')),
  auto_score INTEGER NOT NULL DEFAULT 0,
  manual_score INTEGER NOT NULL DEFAULT 0,
  total_score INTEGER NOT NULL DEFAULT 0,
  started_at TEXT NOT NULL,
  submitted_at TEXT, generation_seed TEXT,
  FOREIGN KEY (exam_id) REFERENCES "exams_old"(id) ON DELETE CASCADE,
  FOREIGN KEY (student_id) REFERENCES users(id) ON DELETE CASCADE
);
CREATE TABLE answers (
  id TEXT PRIMARY KEY,
  attempt_id TEXT NOT NULL,
  question_id TEXT NOT NULL,
  value TEXT NOT NULL,
  auto_score INTEGER,
  manual_score INTEGER,
  feedback TEXT,
  created_at TEXT NOT NULL,
  UNIQUE (attempt_id, question_id),
  FOREIGN KEY (attempt_id) REFERENCES attempts(id) ON DELETE CASCADE,
  FOREIGN KEY (question_id) REFERENCES questions(id) ON DELETE CASCADE
);
CREATE TABLE d1_migrations(
		id         INTEGER PRIMARY KEY AUTOINCREMENT,
		name       TEXT UNIQUE,
		applied_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP NOT NULL
);
CREATE TABLE IF NOT EXISTS "questions" (
  id TEXT PRIMARY KEY,
  bank_id TEXT NOT NULL,
  type TEXT NOT NULL CHECK (type IN ('MCQ', 'TRUE_FALSE', 'SHORT_ANSWER', 'ESSAY', 'IMAGE_UPLOAD')),
  title TEXT NOT NULL,
  prompt TEXT NOT NULL,
  options_json TEXT NOT NULL DEFAULT '[]',
  correct_answer TEXT,
  difficulty TEXT NOT NULL CHECK (difficulty IN ('EASY', 'MEDIUM', 'HARD')),
  tags_json TEXT NOT NULL DEFAULT '[]',
  created_by_id TEXT NOT NULL,
  created_at TEXT NOT NULL,
  FOREIGN KEY (bank_id) REFERENCES question_banks(id) ON DELETE CASCADE,
  FOREIGN KEY (created_by_id) REFERENCES users(id) ON DELETE RESTRICT
);
CREATE TABLE attempt_integrity_events (
  id TEXT PRIMARY KEY,
  attempt_id TEXT NOT NULL,
  exam_id TEXT NOT NULL,
  student_id TEXT NOT NULL,
  event_type TEXT NOT NULL CHECK (
    event_type IN (
      'TAB_HIDDEN',
      'WINDOW_BLUR',
      'FULLSCREEN_EXIT',
      'PASTE_ATTEMPT',
      'COPY_ATTEMPT',
      'BULK_INPUT_BURST',
      'INACTIVE_THEN_BULK_INPUT'
    )
  ),
  severity TEXT NOT NULL CHECK (severity IN ('LOW', 'MEDIUM', 'HIGH')),
  details_json TEXT NOT NULL DEFAULT '{}',
  created_at TEXT NOT NULL,
  FOREIGN KEY (attempt_id) REFERENCES attempts(id) ON DELETE CASCADE,
  FOREIGN KEY (exam_id) REFERENCES "exams_old"(id) ON DELETE CASCADE,
  FOREIGN KEY (student_id) REFERENCES users(id) ON DELETE CASCADE
);
CREATE TABLE communities (
  id TEXT PRIMARY KEY,
  name TEXT NOT NULL,
  description TEXT,
  subject TEXT NOT NULL DEFAULT 'Ерөнхий',
  grade INTEGER NOT NULL DEFAULT 0,
  visibility TEXT NOT NULL DEFAULT 'PUBLIC' CHECK (visibility IN ('PRIVATE', 'PUBLIC')),
  owner_id TEXT NOT NULL,
  created_at TEXT NOT NULL,
  FOREIGN KEY (owner_id) REFERENCES users(id) ON DELETE RESTRICT
);
CREATE TABLE community_members (
  id TEXT PRIMARY KEY,
  community_id TEXT NOT NULL,
  user_id TEXT NOT NULL,
  role TEXT NOT NULL CHECK (role IN ('OWNER', 'MODERATOR', 'MEMBER')),
  joined_at TEXT NOT NULL,
  UNIQUE (community_id, user_id),
  FOREIGN KEY (community_id) REFERENCES communities(id) ON DELETE CASCADE,
  FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE
);
CREATE TABLE community_shared_banks (
  id TEXT PRIMARY KEY,
  community_id TEXT NOT NULL,
  bank_id TEXT NOT NULL,
  shared_by_id TEXT NOT NULL,
  status TEXT NOT NULL DEFAULT 'ACTIVE' CHECK (status IN ('ACTIVE', 'ARCHIVED', 'FEATURED')),
  created_at TEXT NOT NULL,
  UNIQUE (community_id, bank_id),
  FOREIGN KEY (community_id) REFERENCES communities(id) ON DELETE CASCADE,
  FOREIGN KEY (bank_id) REFERENCES question_banks(id) ON DELETE CASCADE,
  FOREIGN KEY (shared_by_id) REFERENCES users(id) ON DELETE RESTRICT
);
CREATE TABLE exam_import_questions (
  id TEXT PRIMARY KEY,
  job_id TEXT NOT NULL REFERENCES "exam_import_jobs_old_fk_fix_prod"(id) ON DELETE CASCADE,
  display_order INTEGER NOT NULL,
  type TEXT NOT NULL CHECK (type IN ('MCQ', 'TRUE_FALSE', 'SHORT_ANSWER', 'ESSAY', 'IMAGE_UPLOAD')),
  title TEXT NOT NULL,
  prompt TEXT NOT NULL,
  options_json TEXT NOT NULL DEFAULT '[]',
  answers_json TEXT NOT NULL DEFAULT '[]',
  score INTEGER NOT NULL DEFAULT 1,
  difficulty TEXT NOT NULL CHECK (difficulty IN ('EASY', 'MEDIUM', 'HARD')),
  source_page INTEGER,
  confidence REAL NOT NULL DEFAULT 0.5,
  needs_review INTEGER NOT NULL DEFAULT 1,
  created_at TEXT NOT NULL
, source_excerpt TEXT, source_block_id TEXT, source_bbox_json TEXT);
CREATE TABLE exams (
  id TEXT PRIMARY KEY,
  class_id TEXT NOT NULL REFERENCES classes(id) ON DELETE CASCADE,
  is_template INTEGER NOT NULL DEFAULT 0,
  source_exam_id TEXT REFERENCES exams(id) ON DELETE SET NULL,
  title TEXT NOT NULL,
  description TEXT,
  mode TEXT NOT NULL CHECK (mode IN ('SCHEDULED', 'OPEN_WINDOW', 'PRACTICE')),
  status TEXT NOT NULL CHECK (status IN ('DRAFT', 'PUBLISHED', 'CLOSED')),
  duration_minutes INTEGER NOT NULL,
  started_at TEXT,
  ends_at TEXT,
  created_by_id TEXT NOT NULL REFERENCES users(id) ON DELETE CASCADE,
  scheduled_for TEXT,
  shuffle_questions INTEGER NOT NULL DEFAULT 0,
  shuffle_answers INTEGER NOT NULL DEFAULT 0,
  generation_mode TEXT NOT NULL DEFAULT 'MANUAL' CHECK (generation_mode IN ('MANUAL', 'RULE_BASED')),
  rules_json TEXT NOT NULL DEFAULT '[]',
  passing_criteria_type TEXT NOT NULL DEFAULT 'PERCENTAGE' CHECK (passing_criteria_type IN ('PERCENTAGE', 'POINTS')),
  passing_threshold INTEGER NOT NULL DEFAULT 40,
  created_at TEXT NOT NULL
);
CREATE TABLE exam_import_jobs ( id TEXT PRIMARY KEY, teacher_id TEXT NOT NULL REFERENCES users(id) ON DELETE CASCADE, question_bank_id TEXT REFERENCES question_banks(id) ON DELETE SET NULL, exam_id TEXT REFERENCES exams(id) ON DELETE SET NULL, storage_key TEXT, file_name TEXT NOT NULL, file_size_bytes INTEGER NOT NULL DEFAULT 0, source_type TEXT NOT NULL CHECK (source_type IN ('PDF')), status TEXT NOT NULL CHECK (status IN ('UPLOADED','PROCESSING','REVIEW','PUBLISHED','FAILED')), title TEXT NOT NULL, extracted_text TEXT, parsed_exam_json TEXT NOT NULL, error_message TEXT, created_at TEXT NOT NULL, updated_at TEXT NOT NULL, extraction_json TEXT, classifier_json TEXT );
DELETE FROM sqlite_sequence;
CREATE INDEX idx_classes_teacher_id ON classes(teacher_id);
CREATE INDEX idx_class_students_class_id ON class_students(class_id);
CREATE INDEX idx_class_students_student_id ON class_students(student_id);
CREATE INDEX idx_question_banks_owner_id ON question_banks(owner_id);
CREATE INDEX idx_exam_questions_exam_id ON exam_questions(exam_id);
CREATE INDEX idx_attempts_exam_id ON attempts(exam_id);
CREATE INDEX idx_attempts_student_id ON attempts(student_id);
CREATE INDEX idx_answers_attempt_id ON answers(attempt_id);
CREATE INDEX idx_questions_bank_id ON questions(bank_id);
CREATE INDEX idx_question_banks_visibility ON question_banks(visibility);
CREATE INDEX idx_question_banks_grade ON question_banks(grade);
CREATE INDEX idx_question_banks_subject ON question_banks(subject);
CREATE INDEX idx_question_banks_topic ON question_banks(topic);
CREATE INDEX idx_attempt_integrity_events_attempt_id
  ON attempt_integrity_events(attempt_id, created_at DESC);
CREATE INDEX idx_attempt_integrity_events_exam_id
  ON attempt_integrity_events(exam_id, created_at DESC);
CREATE INDEX idx_attempt_integrity_events_student_id
  ON attempt_integrity_events(student_id, created_at DESC);
CREATE INDEX idx_communities_owner_id ON communities(owner_id);
CREATE INDEX idx_communities_subject_grade ON communities(subject, grade);
CREATE INDEX idx_community_members_community_id ON community_members(community_id);
CREATE INDEX idx_community_members_user_id ON community_members(user_id);
CREATE INDEX idx_community_shared_banks_community_id ON community_shared_banks(community_id);
CREATE INDEX idx_community_shared_banks_bank_id ON community_shared_banks(bank_id);
CREATE INDEX idx_exam_import_questions_job_order
  ON exam_import_questions (job_id, display_order ASC);
CREATE INDEX idx_exams_class_status
  ON exams (class_id, status);
CREATE INDEX idx_exams_created_by
  ON exams (created_by_id, created_at DESC);
CREATE INDEX idx_exam_import_jobs_teacher_created ON exam_import_jobs (teacher_id, created_at DESC);
